import { setup, assign } from 'xstate';

interface CountdownContext {
  remainingSec: number;
}

type CountdownEvent =
  | { type: 'START' }
  | { type: 'RESET'; seconds: number }
  | { type: 'TICK' };

export const countdownMachine = setup({
  types: {
    context: {} as CountdownContext,
    events: {} as CountdownEvent
  },
  guards: {
    isDone: ({ context }) => context.remainingSec <= 0
  },
  actions: {
    decrement: assign({
      remainingSec: ({ context }) => Math.max(0, context.remainingSec - 1)
    }),
    reset: assign({
      remainingSec: ({ event }) =>
        event.type === 'RESET' ? event.seconds : 0
    })
  },
  delays: {
    oneSecond: () => 1000
  }
}).createMachine({
  id: 'countdown',
  context: { remainingSec: 60 },
  initial: 'idle',
  states: {
    idle: {
      on: { START: { target: 'ticking' } }
    },
    ticking: {
      always: [{ guard: 'isDone', target: 'done' }],
      after: {
        oneSecond: { target: 'ticking', actions: 'decrement', reenter: true }
      },
      on: { RESET: { target: 'idle', actions: 'reset' } }
    },
    done: {
      type: 'final'
    }
  }
});
