import { setup, assign } from 'xstate';

interface HistoryContext {
  past: string[];
  present: string;
  future: string[];
}

type HistoryEvent =
  | { type: 'SET'; value: string }
  | { type: 'UNDO' }
  | { type: 'REDO' }
  | { type: 'CLEAR' };

export const undoRedoMachine = setup({
  types: {
    context: {} as HistoryContext,
    events: {} as HistoryEvent
  },
  guards: {
    canUndo: ({ context }) => context.past.length > 0,
    canRedo: ({ context }) => context.future.length > 0
  },
  actions: {
    set: assign(({ context, event }) => {
      if (event.type !== 'SET') return {};
      return {
        past: [...context.past, context.present],
        present: event.value,
        future: [] as string[]
      };
    }),
    undo: assign(({ context }) => {
      const prev = context.past[context.past.length - 1] ?? context.present;
      return {
        past: context.past.slice(0, -1),
        present: prev,
        future: [context.present, ...context.future]
      };
    }),
    redo: assign(({ context }) => {
      const next = context.future[0] ?? context.present;
      return {
        past: [...context.past, context.present],
        present: next,
        future: context.future.slice(1)
      };
    }),
    clear: assign({
      past: () => [] as string[],
      future: () => [] as string[]
    })
  }
}).createMachine({
  id: 'history',
  context: { past: [], present: '', future: [] },
  initial: 'ready',
  states: {
    ready: {
      on: {
        SET: { actions: 'set' },
        UNDO: { guard: 'canUndo', actions: 'undo' },
        REDO: { guard: 'canRedo', actions: 'redo' },
        CLEAR: { actions: 'clear' }
      }
    }
  }
});
