  types: { context: {} as Ctx, events: {} as Ev },
  actors: { fetchUrl },
  guards: {
    hasJob: ({ context }) => context.queue.length > 0,
    canRetry: ({ context }) => {
      const head = context.queue[0];
      return head !== undefined && head.attempts + 1 < context.maxAttempts;
    }
  },
  actions: {
    enqueue: assign({
      queue: ({ context, event }) => [
        ...context.queue,
        { url: event.url, attempts: 0 }
      ]
    }),
