        if (!head) return context.queue;
        return [{ url: head.url, attempts: head.attempts + 1 }, ...rest];
      }
    }),
    moveToFailed: assign({
      failed: ({ context }) => {
        const head = context.queue[0];
        return head ? [...context.failed, head] : context.failed;
      },
      queue: ({ context }) => context.queue.slice(1)
    })
  }
