  guards: {
    isDifferent: ({ context }) =>
      context.draft.h !== context.committed.h ||
      context.draft.s !== context.committed.s ||
      context.draft.l !== context.committed.l,
    isSame: ({ context }) =>
      context.draft.h === context.committed.h &&
      context.draft.s === context.committed.s &&
      context.draft.l === context.committed.l
  },
  actions: {
    patch: assign({
      draft: ({ context, event }) =>
        event.type === 'SET' ? { ...context.draft, ...event.patch } : context.draft
    }),
    markDirty: assign({ dirty: () => true }),
    markClean: assign({ dirty: () => false }),
    commit: assign({ committed: ({ context }) => context.draft })
  }
}).createMachine({
  id: 'dirtyColor',
  context: {
    draft: { h: 0, s: 50, l: 50 },
    committed: { h: 0, s: 50, l: 50 },
    dirty: false
  },
