  states: {
    clean: {
      always: [{ guard: 'isDifferent', target: 'dirtyState', actions: 'markDirty' }],
      on: { SET: { actions: 'patch' } }
    },
    dirtyState: {
      always: [{ guard: 'isSame', target: 'clean', actions: 'markClean' }],
      on: {
        SET: { actions: 'patch' },
        COMMIT: { target: 'clean', actions: ['commit', 'markClean'] }
