type Ev =
  | { type: 'PREV' }
  | { type: 'NEXT' }
  | { type: 'PICK'; day: number };

export const calendarGridMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    canGoPrev: ({ context }) =>
      context.cursor.y > context.minYear ||
      (context.cursor.y === context.minYear && context.cursor.m > 0)
  },
  actions: {
    goPrev: assign(({ context }) => {
      if (context.cursor.m === 0) {
        return { cursor: { y: context.cursor.y - 1, m: 11 } };
      }
      return { cursor: { y: context.cursor.y, m: context.cursor.m - 1 } };
    }),
    goNext: assign(({ context }) => {
      if (context.cursor.m === 11) {
        return { cursor: { y: context.cursor.y + 1, m: 0 } };
      }
      return { cursor: { y: context.cursor.y, m: context.cursor.m + 1 } };
    }),
    pick: assign({
      selected: ({ context, event }) =>
        event.type === 'PICK'
          ? { y: context.cursor.y, m: context.cursor.m, d: event.day }
          : context.selected
    })
  }
}).createMachine({
  id: 'calendar',
  context: {
    cursor: { y: 2025, m: 3 },
    selected: null,
    minYear: 2000
  },
  on: {
    PREV: { guard: 'canGoPrev', actions: 'goPrev' },
    NEXT: { actions: 'goNext' },
    PICK: { actions: 'pick' }
  }
});
